31	        }
32	    }
33	
34	    /// True when every setup prerequisite is satisfied.
35	    pub fn is_setup_complete(&self) -> bool {
36	        self.config_exists
37	            && self.model_installed
38	            && self.uinput_accessible
39	            && self.ptt_configured
40	    }
41	
42	    /// Ordered list of steps that are not yet done (wizard order).
43	    pub fn steps_remaining(&self) -> Vec<SetupStep> {
44	        let mut steps = Vec::new();
45	        if !self.config_exists {
46	            steps.push(SetupStep::CreateConfig);
47	        }
48	        if !self.model_installed {
49	            steps.push(SetupStep::InstallModel);
50	        }
